static void cct_rt_socket_enable_reuseaddr(int fd) {
    int yes = 1;
    (void)setsockopt(fd, SOL_SOCKET, SO_REUSEADDR, &yes, (socklen_t)sizeof(yes));
}

static void cct_rt_socket_validate_port(long long port) {
    if (port < 0 || port > 65535) cct_rt_fail("sock port invalido");
}

static int cct_rt_socket_is_local_host(const char *host) {
    if (!host || !*host) return 1;
    return strcmp(host, "127.0.0.1") == 0;
}

static void cct_rt_socket_make_unix_path(long long port, char out_path[108]) {
    cct_rt_socket_validate_port(port);
    int n = snprintf(out_path, 108, "tests/.tmp/cct_sock_%lld.sock", port);
    if (n <= 0 || n >= 108) cct_rt_fail("sock unix path invalido");
}

static void *cct_rt_socket_tcp(void) {
#ifdef _WIN32
    cct_rt_fail("socket_tcp unsupported on _WIN32");
    return NULL;
#else
    int fd = socket(AF_INET, SOCK_STREAM, 0);
    if (fd < 0) {
        cct_rt_socket_set_last_error("socket tcp create falhou");
        cct_rt_fractum_throw_str("socket tcp create falhou");
        return (void*)&cct_rt_null_sentinel;
    }
    cct_rt_socket_clear_last_error();
    return (void*)cct_rt_socket_alloc(fd, SOCK_STREAM, AF_INET);
#endif
}

